      c = util::f16_to_f32(static_cast<uint16_t>((inst_.opsel & 4) ? (raw2 >> 16) : raw2));
    else
      c = std::bit_cast<float>(raw2);
    if (inst_.neg & 1)
      a = -a;
    if (inst_.neg & 2)
      b = -b;
    if (inst_.neg & 4)
      c = -c;
    float result = a * b + c;
    if (inst_.clamp)
      result = std::clamp(result, 0.0f, 1.0f);
